= impostorIndex,                word: i == impostorIndex ? impostorWord : word,                category: cat            )        }                currentPlayerIndex = 0        isRoleRevealed = false        isScreenLocked = true       // pass screen shows FIRST        currentPhase = .roleReveal    }        //Role Reveal Flow    var currentPlayerName: String {        guard currentPlayerIndex < playerNames.count else {            return ""        }        return playerNames[currentPlayerIndex]    }        // Called when player taps "Reveal My Word"    func revealRole() {        isRoleRevealed = true    }        // Called when "I have the phone" is tapped    // just unlocks so tap to reveal shows    func confirmPassed() {        isScreenLocked = false    }        // Called when "Done — Lock Screen" is tapped    // advances to next player or moves to discussion    func doneViewing() {        isRoleRevealed = false                if currentPlayerIndex < playerNames.count - 1 {            currentPlayerIndex += 1            isScreenLocked = true   // lock for next player        } else {            // Everyone has seen their word            currentPhase = .discussion            startDiscussionTimer()        }    }        func roleFor(_ name: String) -> LocalRole? {        assignedRoles[name]    }        //Discussion Timer    func startDiscussionTimer() {        discussionTimeLeft = 180        timer?.invalidate()        timer = Timer.scheduledTimer(            withTimeInterval: 1,            repeats: true        ) { [weak self] _ in            guard let self else { return }            Task { @MainActor in                if self.discussionTimeLeft > 0 {                    self.discussionTimeLeft -= 1                } else {                    self.timer?.invalidate()                    self.currentPhase = .voting                }            }        }    }        func skipToVoting() {        timer?.invalidate()        currentPhase = .voting    }        //Voting    var alivePlayers: [String] {        playerNames.filter { !eliminatedPlayers.contains($0) }    }        var allVotesCast: Bool {        alivePlayers.allSatisfy { votes[$0] != nil }    }        func castVote(voter: String, target: String) {        votes[voter] = target        if allVotesCast { tallyVotes() }    }        private func tallyVotes() {        let tally = Dictionary(            grouping: votes.values,            by: { $0 }        ).mapValues { $0.count }                guard let eliminated = tally.max(            by: { $0.value < $1.value }        )?.key else { return }                eliminatedPlayers.append(eliminated)        votes = [:]        currentPhase = .results    }        var lastEliminated: String? {        eliminatedPlayers.last    }        var lastEliminatedWasImpostor: Bool {        lastEliminated == impostorName    }        //Continue After Results    func continueAfterResults() {        if lastEliminatedWasImpostor || alivePlayers.count <= 2 {            currentPhase = .gameOver        } else {            votes = [:]            currentPhase = .discussion            startDiscussionTimer()        }    }        var crewWon: Bool {        eliminatedPlayers.contains(impostorName)    }        //Reset    func resetGame() {        playerNames = []        assignedRoles = [:]        votes = [:]        eliminatedPlayers = []        impostorName = ""        category = ""        secretWord = ""        currentPlayerIndex = 0        isRoleRevealed = false        isScreenLocked = false        currentPhase = .setup        timer?.invalidate()        timer = nil    }}